function extractUrls(text: string): string[] {
  const urlRegex = /https?:\/\/[^\s<>"'\)\]]+/g;
  const matches = text.match(urlRegex) || [];
  const cleaned = matches.map(url => url.replace(/[.,;:!?]+$/, ''));
  const seen = new Set<string>();
  const result: string[] = [];
  for (const url of cleaned) {
    if (!seen.has(url)) {
      seen.add(url);
      result.push(url);
    }
  }
  return result;
}
